package com.flowmind.user.mapper;import com.flowmind.common.core.IdGenerator;import com.flowmind.user.entity.UserEntity;import org.springframework.stereotype.Repository;import java.util.*;import java.util.concurrent.ConcurrentHashMap;@Repository public class UserMapper{private final Map<String,UserEntity> users=new ConcurrentHashMap<>();public UserMapper(){save(new UserEntity(1L,"admin","123456","FlowMind ???","ADMIN"));save(new UserEntity(2L,"demo","123456","???? Demo","OPERATOR"));}public Optional<UserEntity> findByUsername(String username){return Optional.ofNullable(users.get(username));}public UserEntity save(UserEntity u){if(u.getId()==null)u.setId(IdGenerator.nextId());users.put(u.getUsername(),u);return u;}}
